function getSimplecastConfig() {
	const env = getEnv()
	return {
		podcastId: env.CHATS_WITH_KENT_PODCAST_ID,
		headers: { authorization: `Bearer ${env.SIMPLECAST_KEY}` },
		seasonsCacheKey: `simplecast:seasons:${env.CHATS_WITH_KENT_PODCAST_ID}`,
	}
}

// Episodes can be fetched concurrently from multiple seasons (and from multiple
// requests). Cap the total in-flight episode-detail requests to reduce 429s.
const simplecastEpisodeDetailsLimit = pLimit(3)

const cwkCachedLinkSchema = z
	.object({
		name: z.string().min(1),
		url: z.string().min(1),
	})
	.passthrough()

const cwkCachedGuestSchema = z
	.object({
		name: z.string().min(1),
		company: z.string().optional(),
		github: z.string().optional(),
		x: z.string().optional(),
	})
	.passthrough()

const cwkCachedMetaSchema = z
	.object({
		keywords: z.array(z.string()).optional(),
	})
	.catchall(z.string())
	.optional()

const cwkCachedEpisodeSchema = z
	.object({
		slug: z.string().min(1),
		title: z.string().min(1),
		meta: cwkCachedMetaSchema,
		descriptionHTML: z.string(),
		description: z.string(),
		summaryHTML: z.string(),
		publishedAt: z.string().min(1),
		updatedAt: z.string().min(1),
		seasonNumber: z.number(),
		episodeNumber: z.number(),
		homeworkHTMLs: z.array(z.string()),
		resources: z.array(cwkCachedLinkSchema),
		image: z.string().min(1),
		guests: z.array(cwkCachedGuestSchema),
		duration: z.number(),
		transcriptHTML: z.string(),
		simpleCastId: z.string().min(1),
		mediaUrl: z.string().min(1),
		youtubeVideoId: z.string().min(1).optional(),
	})
	.passthrough()

const cwkCachedSeasonsSchema = z.array(
	z
		.object({
			seasonNumber: z.number(),
			episodes: z.array(cwkCachedEpisodeSchema),
		})
		.passthrough(),
)

const getCachedSeasons = async ({
	request,
	forceFresh,
	timings,
	signal,
}: {
	request: Request
	forceFresh?: boolean
	timings?: Timings
	signal?: AbortSignal
}) => {
	try {
		return await cachified({
			key: getSimplecastConfig().seasonsCacheKey,
			cache,
			request,
			timings,
			// while we're actively publishing the podcast, let's have the cache be
			// shorter
			ttl: 1000 * 60 * 5,
			// ttl: 1000 * 60 * 60 * 24 * 7,
			staleWhileRevalidate: 1000 * 60 * 60 * 24 * 30,
			getFreshValue: () => getSeasons({ request, forceFresh, timings, signal }),
			forceFresh,
			checkValue: cwkCachedSeasonsSchema,
		})
	} catch (error: unknown) {
		if (isAbortError(error)) return []
		console.error(
			`simplecast: cachified failed to resolve seasons, returning empty fallback`,
			error,
		)
		return []
	}
}

async function getCachedEpisode(
	episodeId: string,
	{
		request,
		forceFresh,
		timings,
		signal,
	}: {
		request: Request
		forceFresh?: boolean
		timings?: Timings
		signal?: AbortSignal
	},
) {
	const key = `simplecast:episode:${episodeId}`
	try {
		return await cachified({
			cache,
			request,
			timings,
			key,
			ttl: 1000 * 60 * 60 * 24 * 7,
			staleWhileRevalidate: 1000 * 60 * 60 * 24 * 30,
			getFreshValue: () => getEpisode(episodeId, { signal }),
			forceFresh,
			checkValue: cwkCachedEpisodeSchema,
		})
	} catch (error: unknown) {
		if (isAbortError(error)) return null
		console.error(
			`simplecast: failed to load episode ${episodeId}, omitting from results`,
			error,
		)
		return null
	}
}

async function getSeasons({
	request,
	forceFresh,
	timings,
	signal,
}: {
	request: Request
	forceFresh?: boolean
	timings?: Timings
	signal?: AbortSignal
}) {
	throwIfAborted(signal)
	const { podcastId, headers } = getSimplecastConfig()
	const seasonsJson = simplecastSeasonsResponseSchema.parse(
		await fetchJsonWithRetryAfter<unknown>(
			`https://api.simplecast.com/podcasts/${podcastId}/seasons`,
			{
				headers,
				label: `simplecast seasons (${podcastId})`,
				retryOn5xx: true,
				signal,
			},
		),
	)
	const { collection } = seasonsJson

	const limit = pLimit(2)
	const seasons = await Promise.all(
		collection.map(({ href, number }) =>
			limit(async () => {
				throwIfAborted(signal)
				const seasonId = new URL(href).pathname.split('/').slice(-1)[0]
				if (!seasonId) {
					console.error(
						`Could not determine seasonId from ${href} for season ${number}`,
					)
					return
				}
				const episodes = await getEpisodes(seasonId, {
					request,
					forceFresh,
					timings,
					signal,
				})
				if (!episodes.length) return null

				return { seasonNumber: number, episodes }
			}),
		),
	).then((s) => s.filter(typedBoolean))

	return sortBy(seasons, (s) => Number(s.seasonNumber))
}

async function getEpisodes(
	seasonId: string,
	{
		request,
		forceFresh,
		timings,
		signal,
	}: {
		request: Request
		forceFresh?: boolean
		timings?: Timings
		signal?: AbortSignal
	},
) {
	throwIfAborted(signal)
	const { headers } = getSimplecastConfig()
	const url = new URL(`https://api.simplecast.com/seasons/${seasonId}/episodes`)
	url.searchParams.set('limit', '300')
	const listJson = simplecastEpisodesListResponseSchema.parse(
		await fetchJsonWithRetryAfter<unknown>(url.toString(), {
			headers,
			label: `simplecast season ${seasonId} episodes list`,
			retryOn5xx: true,
			signal,
		}),
	)
	const { collection } = listJson

	// Fetch episode details. Cached reads are fast; network refreshes are capped
	// globally in `getEpisode` via `simplecastEpisodeDetailsLimit`.
	const episodes = await Promise.all(
		collection
			.filter(({ status, is_hidden }) => status === 'published' && !is_hidden)
			.map(({ id }) =>
				getCachedEpisode(id, { request, forceFresh, timings, signal }),
			),
	)
	return episodes.filter(typedBoolean)
}

async function getEpisode(
	episodeId: string,
	{ signal }: { signal?: AbortSignal } = {},
) {
	throwIfAborted(signal)
	const { headers } = getSimplecastConfig()
	const json = simplecastEpisodeSchema.parse(
		await simplecastEpisodeDetailsLimit(() =>
			fetchJsonWithRetryAfter<unknown>(
				`https://api.simplecast.com/episodes/${episodeId}`,
				{
					headers,
					label: `simplecast episode ${episodeId}`,
					retryOn5xx: true,
					signal,
				},
			),
		),
	)

	const {
		id,
		is_published,
		published_at,
		updated_at,
		slug,
		transcription: transcriptMarkdown,
		long_description: summaryMarkdown,
		description: descriptionMarkdown,
		image_url,
		number,
		duration,
		title,
		season: { number: seasonNumber },
		keywords: keywordsData,
		enclosure_url: mediaUrl,
	} = json

	if (!is_published) {
		return null
	}

	const keywords = keywordsData?.collection?.map(({ value }) => value) ?? []
	const [
		{ descriptionHTML, youtubeVideoId: descriptionYouTubeVideoId },
		{ summaryHTML, homeworkHTMLs, resources, guests, youtubeVideoId },
		transcriptHTML,
	] = await Promise.all([
		parseDescriptionMarkdown(descriptionMarkdown),
		summaryMarkdown
			? parseSummaryMarkdown(summaryMarkdown, `${id}-${slug}`)
			: {
					summaryHTML: '',
					homeworkHTMLs: [],
					resources: [],
					guests: [],
					youtubeVideoId: null,
				},
		parseEpisodeMarkdown(transcriptMarkdown),
	])

	// Simplecast exposes both published and updated timestamps; fall back to
	// `updated_at` so older/malformed episodes still render a date.
	const publishedAt = published_at ?? updated_at

	const cwkEpisode: CWKEpisode = {
		transcriptHTML,
		descriptionHTML,
		description: await stripHtml(descriptionHTML),
		summaryHTML,
		guests,
		slug,
		resources,
		image: image_url,
		episodeNumber: number,
		publishedAt,
		updatedAt: updated_at,
		homeworkHTMLs,
		seasonNumber,
		duration,
		title,
		meta: {
			keywords,
		},
		simpleCastId: episodeId,
		mediaUrl,
		youtubeVideoId: youtubeVideoId ?? descriptionYouTubeVideoId ?? undefined,
	}
	return cwkEpisode
}

function removeEls<ItemType>(array: Array<ItemType>, ...els: Array<ItemType>) {
	return array.filter((el) => !els.includes(el))
}

function autoAffiliates() {
	return async function affiliateTransformer(tree: H.Root) {
		visit(tree, 'element', function visitor(linkNode: H.Element) {
			if (linkNode.tagName !== 'a') return
			if (!linkNode.properties) return
			if (typeof linkNode.properties.href !== 'string') return
			if (linkNode.properties.href.includes('amazon.com')) {
				const amazonUrl = new URL(linkNode.properties.href)
				if (!amazonUrl.searchParams.has('tag')) {
					amazonUrl.searchParams.set('tag', 'kentcdodds-20')
					linkNode.properties.href = amazonUrl.toString()
				}
			}
			if (linkNode.properties.href.includes('egghead.io')) {
				const eggheadUrl = new URL(linkNode.properties.href)
				if (!eggheadUrl.searchParams.has('af')) {
					eggheadUrl.searchParams.set('af', '5236ad')
					linkNode.properties.href = eggheadUrl.toString()
				}
			}
		})
	}
}

function findYouTubeVideoIdInNodes(nodes: Array<U.Node>) {
	let youtubeVideoId: string | null = null

	for (const node of nodes) {
		visit(node, 'link', (link: M.Link) => {
			if (youtubeVideoId) return
			youtubeVideoId = getYouTubeVideoId(link.url)
		})

		if (youtubeVideoId) break

		visit(node, 'text', (text: M.Text) => {
			if (youtubeVideoId) return
			youtubeVideoId = findFirstYouTubeVideoIdInText(text.value)
		})

		if (youtubeVideoId) break
	}

	return youtubeVideoId
}

function isYouTubeOnlyNode(node: M.PhrasingContent) {
	if (node.type === 'link') {
		return Boolean(getYouTubeVideoId(node.url))
	}

	if (node.type === 'text') {
		const value = node.value.trim()
		if (!value) return false

		const youtubeVideoId = findFirstYouTubeVideoIdInText(value)
		if (!youtubeVideoId) return false

		const textWithoutYouTubeUrls = value.replace(/https?:\/\/\S+/g, (match) => {
			const candidate = match.replace(/[<>"')\],.;!?]+$/g, '')
			return getYouTubeVideoId(candidate) ? '' : match
		})
		return /^[\s\p{P}]*$/u.test(textWithoutYouTubeUrls)
	}

	return false
}

function isYouTubeOnlyParagraph(node: U.Node): node is M.Paragraph {
	if (node.type !== 'paragraph') return false
	const paragraphNode = node as M.Paragraph
	return paragraphNode.children.every((child: M.PhrasingContent) => {
		if (child.type === 'text' && /^[\s\p{P}]*$/u.test(child.value)) return true
		return isYouTubeOnlyNode(child)
	})
}

async function parseEpisodeMarkdown(input: string | null | undefined) {
	if (!input) return ''

	const isHTMLInput = input.trim().startsWith('<')
	if (isHTMLInput) {
		return input
	}
	const result = await unified()
		.use(parseMarkdown)
		.use(remark2rehype)
		.use(rehypeStringify)
		.process(input)

	return result.value.toString()
}

async function parseDescriptionMarkdown(
	descriptionInput: string | null | undefined,
): Promise<Pick<CWKEpisode, 'descriptionHTML' | 'youtubeVideoId'>> {
	if (!descriptionInput) {
		return { descriptionHTML: '', youtubeVideoId: undefined }
	}

	const isHTMLInput = descriptionInput.trim().startsWith('<')
	let youtubeVideoId: string | undefined
	let removedYouTubeOnlyParagraphs = false

	const result = await unified()
		.use(isHTMLInput ? parseHtml : parseMarkdown)
		.use(isHTMLInput ? rehype2remark : () => {})
		.use(function extractDescriptionMetadata() {
			return function transformer(tree: M.Root) {
				tree.children = tree.children.filter((child) => {
					if (!isYouTubeOnlyParagraph(child)) return true
					removedYouTubeOnlyParagraphs = true
					youtubeVideoId ??= findYouTubeVideoIdInNodes([child]) ?? undefined
					return false
				})
			}
		})
		.use(remark2rehype)
		.use(rehypeStringify)
		.process(descriptionInput)

	if (isHTMLInput && !removedYouTubeOnlyParagraphs) {
		return {
			descriptionHTML: descriptionInput,
			youtubeVideoId:
				youtubeVideoId ?? findFirstYouTubeVideoIdInText(descriptionInput) ?? undefined,
		}
	}

	return {
		descriptionHTML: result.value.toString(),
		youtubeVideoId:
			youtubeVideoId ?? findFirstYouTubeVideoIdInText(descriptionInput) ?? undefined,
	}
}

async function parseSummaryMarkdown(
	summaryInput: string,
	errorKey: string,
): Promise<
	Pick<
		CWKEpisode,
		'summaryHTML' | 'resources' | 'guests' | 'homeworkHTMLs' | 'youtubeVideoId'
	>
> {
	const isHTMLInput = summaryInput.trim().startsWith('<')
	const resources: CWKEpisode['resources'] = []
	const guests: CWKEpisode['guests'] = []
	const homeworkHTMLs: CWKEpisode['homeworkHTMLs'] = []
	let youtubeVideoId: string | null = null

	const result = await unified()
		.use(isHTMLInput ? parseHtml : parseMarkdown)
		.use(isHTMLInput ? rehype2remark : () => {})
		.use(function extractMetaData() {
			return function transformer(tree: M.Root) {
				type Section = {
					children: Array<U.Node>
					remove: () => void
				}
				const sections: Record<string, Section> = {}
				visit(tree, 'heading', (heading: M.Heading, index, parent) => {
					if (!parent) {
						console.error(heading, `${errorKey} heading without a parent`)
						return
					}
					if (heading.depth !== 3) return

					const nextHeading = parent.children
						.slice((index ?? 0) + 1)
						// the rule is wrong here...

						.find((n) => n.type === 'heading' && (n as M.Heading).depth >= 3)
					const endOfSection = nextHeading
						? // @ts-expect-error no idea why typescript says something I found can't be indexed 🤷‍♂️
							parent.children.indexOf(nextHeading)
						: parent.children.length

					const headingChildren = parent.children.slice(
						(index ?? 0) + 1,
						endOfSection,
					)
					const sectionTitle = (heading.children[0] as M.Text | undefined)
						?.value
					if (!sectionTitle) {
						console.error(`${errorKey}: Section with no title`, heading)
						return
					}
					sections[sectionTitle] = {
						children: headingChildren,
						remove() {
							parent.children = removeEls(
								parent.children,
								heading,
								...headingChildren,
							)
						},
					}
				})

				for (const [sectionTitle, { children, remove }] of Object.entries(
					sections,
				)) {
					// can't remove elements from an array while you're iterating
					// over that array, so we have to do it afterwards

					if (/kent c. dodds/i.test(sectionTitle)) {
						// we don't need to add any meta data for Kent.
						remove()
						continue
					}
					if (/resources/i.test(sectionTitle)) {
						remove()
						for (const child of children) {
							visit(child, 'listItem', (listItem: M.ListItem) => {
								visit(listItem, 'link', (link: M.Link) => {
									visit(link, 'text', (text: M.Text) => {
										resources.push({
											name: text.value,
											url: link.url,
										})
									})
								})
							})
						}
					}
					if (/^(video|youtube|youtube video)$/i.test(sectionTitle)) {
						remove()
						youtubeVideoId ??= findYouTubeVideoIdInNodes(children)
						continue
					}
					if (/homework/i.test(sectionTitle)) {
						remove()
						for (const child of children) {
							visit(child, 'listItem', (listItem: M.ListItem) => {
								homeworkHTMLs.push(
									listItem.children
										.map((c) => {
											const hastC = mdastToHast(c)

											if (!hastC) {
												console.error(
													`${errorKey}: list item child that returned no hAST.`,
													c,
												)
												throw new Error(
													'This should not happen. mdastToHast of a list item child is falsy.',
												)
											}
											return hastToHtml(hastC)
										})
										.join(''),
								)
							})
						}
					}
					if (/^guest/i.test(sectionTitle)) {
						remove()
						for (const child of children) {
							let company, github, x
							visit(child, 'listItem', (listItem: M.ListItem) => {
								// this error handling makes me laugh and cry
								// definitely better error messages than we'd get
								// if we just pretended this could never happen...
								// ... and you know what... they did happen and I'm glad I added
								// this error handling 😂
								const paragraph = listItem.children[0]
								if (paragraph?.type !== 'paragraph') {
									console.error(
										`${errorKey}: guest listItem first child is not a paragraph`,
										child,
									)
									return
								}
								const [text, link] = paragraph.children
								if (text?.type !== 'text') {
									console.error(
										`${errorKey}: guest listItem first child's first child is not a text node`,
										child,
									)
									return
								}
								if (link?.type !== 'link') {
									console.error(
										`${errorKey}: guest listItem first child's second child is not a link node`,
										child,
									)
									return
								}
								const linkText = link.children[0]
								if (linkText?.type !== 'text') {
									console.error(
										`${errorKey}: guest listItem first child's second child's first child is not a text node`,
										child,
									)
									return
								}
								const { value: type } = text
								const { value: name } = linkText
								if (/company/i.test(type)) {
									company = name
								}
								if (/github/i.test(type)) {
									github = name.replace('@', '')
								}
								if (/twitter/i.test(type)) {
									x = name.replace('@', '')
								}
								if (/x/i.test(type)) {
									x = name.replace('@', '')
								}
								if (/𝕏/i.test(type)) {
									x = name.replace('@', '')
								}
							})
							guests.push({
								name: sectionTitle.replace(/^guest:?/i, '').trim(),
								company,
								github,
								x,
							})
						}
					}
				}

				const [lastElement] = tree.children.slice(-1)
				if (lastElement?.type === 'thematicBreak') {
					tree.children = removeEls(tree.children, lastElement)
				}
			}
		})
		.use(remark2rehype)
		.use(autoAffiliates)
		.use(rehypeStringify)
		.process(summaryInput)

	const summaryHTML = result.value.toString()
	return {
		summaryHTML,
		homeworkHTMLs,
		resources,
		guests,
		youtubeVideoId: youtubeVideoId ?? undefined,
	}
}

async function getSeasonListItems({
	request,
	forceFresh,
	timings,
	signal,
}: {
	request: Request
	forceFresh?: boolean
	timings?: Timings
	signal?: AbortSignal
}) {
	const seasons = await getCachedSeasons({
		request,
		forceFresh,
		timings,
		signal,
	})
	const listItemSeasons: Array<CWKSeason> = []
	for (const season of seasons) {
		listItemSeasons.push({
			seasonNumber: season.seasonNumber,
			episodes: season.episodes.map((episode) => {
				return omit(
					episode,
					'homeworkHTMLs',
					'resources',
					'summaryHTML',
					'transcriptHTML',
					'meta',
					'descriptionHTML',
				)
			}),
		})
	}
	return listItemSeasons
}

export {
	getSeasonListItems,
	getCachedSeasons as getSeasons,
	parseDescriptionMarkdown,
	parseSummaryMarkdown,
}
